1	/**
2	 * File Reference Validator
3	 *
4	 * Validates cross-file references in BMAD source files (agents, workflows, tasks, steps).
5	 * Catches broken file paths, missing referenced files, and absolute path leaks.
6	 *
7	 * What it checks:
8	 * - {project-root}/_bmad/ references in YAML and markdown resolve to real src/ files
9	 * - Relative path references (./file.md, ../data/file.csv) point to existing files
10	 * - exec="..." and <invoke-task> targets exist
11	 * - Step metadata (thisStepFile, nextStepFile) references are valid
12	 * - Load directives (Load: `./file.md`) target existing files
13	 * - No absolute paths (/Users/, /home/, C:\) leak into source files
14	 *
15	 * What it does NOT check (deferred):
16	 * - {installed_path} variable interpolation (self-referential, low risk)
17	 * - {{mustache}} template variables (runtime substitution)
18	 * - {config_source}:key dynamic YAML dereferences
19	 *
20	 * Usage:
21	 *   node tools/validate-file-refs.js            # Warn on broken references (exit 0)
22	 *   node tools/validate-file-refs.js --strict    # Fail on broken references (exit 1)
23	 *   node tools/validate-file-refs.js --verbose   # Show all checked references
24	 *
25	 * Default mode is warning-only (exit 0) so adoption is non-disruptive.
26	 * Use --strict when you want CI or pre-commit to enforce valid references.
27	 */
28	
29	const fs = require('node:fs');
30	const path = require('node:path');
31	// Dev-only tool — yaml and csv-parse are in devDependencies (runs via npm run quality / CI only)
32	const yaml = require('yaml');
33	const { parse: parseCsv } = require('csv-parse/sync');
34	
35	const PROJECT_ROOT = path.resolve(__dirname, '..');
36	const SRC_DIR = path.join(PROJECT_ROOT, 'src');
37	const VERBOSE = process.argv.includes('--verbose');
38	const STRICT = process.argv.includes('--strict');
39	
40	// --- Constants ---
41	
42	// File extensions to scan
43	const SCAN_EXTENSIONS = new Set(['.yaml', '.yml', '.md', '.xml', '.csv']);
44	
45	// Skip directories
46	const SKIP_DIRS = new Set(['node_modules', '.git']);
47	
48	// Pattern: {project-root}/_bmad/ references
49	const PROJECT_ROOT_REF = /\{project-root\}\/_bmad\/([^\s'"<>})\]`]+)/g;
50	
51	// Pattern: {_bmad}/ shorthand references
52	const BMAD_SHORTHAND_REF = /\{_bmad\}\/([^\s'"<>})\]`]+)/g;
53	
54	// Pattern: exec="..." attributes
55	const EXEC_ATTR = /exec="([^"]+)"/g;
56	
57	// Pattern: <invoke-task> content
58	const INVOKE_TASK = /<invoke-task>([^<]+)<\/invoke-task>/g;
59	
60	// Pattern: relative paths in quotes
61	const RELATIVE_PATH_QUOTED = /['"](\.\.\/?[^'"]+\.(?:md|yaml|yml|xml|json|csv|txt))['"]/g;
62	const RELATIVE_PATH_DOT = /['"](\.\/[^'"]+\.(?:md|yaml|yml|xml|json|csv|txt))['"]/g;
63	
64	// Pattern: step metadata
65	const STEP_META = /(?:thisStepFile|nextStepFile|continueStepFile|skipToStepFile|altStepFile|workflowFile):\s*['"](\.[^'"]+)['"]/g;
66	
67	// Pattern: Load directives
68	const LOAD_DIRECTIVE = /Load[:\s]+`(\.[^`]+)`/g;
69	
70	// Pattern: absolute path leaks
71	const ABS_PATH_LEAK = /(?:\/Users\/|\/home\/|[A-Z]:\\\\)/;
72	
73	// --- Output Escaping ---
74	
75	function escapeAnnotation(str) {
76	  return str.replaceAll('%', '%25').replaceAll('\r', '%0D').replaceAll('\n', '%0A');
77	}
78	
79	function escapeTableCell(str) {
80	  return String(str).replaceAll('|', String.raw`\|`);
81	}
82	
83	// Path prefixes/patterns that only exist in installed structure, not in source
84	const INSTALL_ONLY_PATHS = ['_config/', '_memory/'];
85	
86	// Files that are generated at install time and don't exist in the source tree
87	const INSTALL_GENERATED_FILES = ['config.yaml', 'config.user.yaml', 'VERSION', 'package.json'];
88	
89	// Variables that indicate a path is not statically resolvable
90	const UNRESOLVABLE_VARS = [
91	  '{output_folder}',
92	  '{value}',
93	  '{timestamp}',
94	  '{config_source}:',
95	  '{installed_path}',
96	  '{shared_path}',
97	  '{planning_artifacts}',
98	  '{research_topic}',
99	  '{user_name}',
100	  '{communication_language}',
101	  '{epic_number}',
102	  '{next_epic_num}',
103	  '{epic_num}',
104	  '{part_id}',
105	  '{count}',
106	  '{date}',
107	  '{outputFile}',
108	  '{nextStepFile}',
109	  '{sidecar_path}',
110	  '{skills_output_folder}',
111	  '{forge_data_folder}',
112	  '{project_name}',
113	  '{document_output_language}',
114	  '{skf_folder}',
115	];
116	
117	// --- File Discovery ---
118	
119	function getSourceFiles(dir) {
120	  const files = [];
121	
122	  function walk(currentDir) {
123	    const entries = fs.readdirSync(currentDir, { withFileTypes: true });
124	
125	    for (const entry of entries) {
126	      if (SKIP_DIRS.has(entry.name)) continue;
127	
128	      const fullPath = path.join(currentDir, entry.name);
129	
130	      if (entry.isDirectory()) {
131	        walk(fullPath);
132	      } else if (entry.isFile() && SCAN_EXTENSIONS.has(path.extname(entry.name))) {
133	        files.push(fullPath);
134	      }
135	    }
136	  }
137	
138	  walk(dir);
139	  return files;
140	}
141	
142	// --- Code Block Stripping ---
143	
144	function stripCodeBlocks(content) {
145	  return content.replaceAll(/```[\s\S]*?```/g, (m) => m.replaceAll(/[^\n]/g, ''));
146	}
147	
148	function stripJsonExampleBlocks(content) {
149	  // Strip bare JSON example blocks: { and } each on their own line.
150	  // These are example/template data (not real file references).
151	  return content.replaceAll(/^\{\s*\n(?:.*\n)*?^\}\s*$/gm, (m) => m.replaceAll(/[^\n]/g, ''));
152	}
153	
154	// --- Path Mapping ---
155	
156	function mapInstalledToSource(refPath) {
157	  // Strip {project-root}/_bmad/ or {_bmad}/ prefix
158	  let cleaned = refPath.replace(/^\{project-root\}\/_bmad\//, '').replace(/^\{_bmad\}\//, '');
159	
160	  // Also handle bare _bmad/ prefix (seen in some invoke-task)
161	  cleaned = cleaned.replace(/^_bmad\//, '');
162	
163	  // Skip install-only paths (generated at install time, not in source)
164	  if (isInstallOnly(cleaned)) return null;
165	
166	  // Map installed module names to their source directory names
167	  // _bmad/skf/ → src/ (SKF module)
168	  if (cleaned.startsWith('skf/')) {
169	    return path.join(SRC_DIR, cleaned.slice('skf/'.length));
170	  }
171	
172	  // Fallback: map directly under src/
173	  return path.join(SRC_DIR, cleaned);
174	}
175	
176	// --- Reference Extraction ---
177	
178	function isResolvable(refStr) {
179	  // Skip refs containing unresolvable runtime variables
180	  if (refStr.includes('{{')) return false;
181	  // Skip node_modules references (runtime dependency paths)
182	  if (refStr.includes('node_modules')) return false;
183	  for (const v of UNRESOLVABLE_VARS) {
184	    if (refStr.includes(v)) return false;
185	  }
186	  return true;
187	}
188	
189	function isInstallOnly(cleanedPath) {
190	  // Skip paths that only exist in the installed _bmad/ structure, not in src/
191	  for (const prefix of INSTALL_ONLY_PATHS) {
192	    if (cleanedPath.startsWith(prefix)) return true;
193	  }
194	  // Skip files that are generated during installation
195	  const basename = path.basename(cleanedPath);
196	  for (const generated of INSTALL_GENERATED_FILES) {
197	    if (basename === generated) return true;
198	  }
199	  return false;
200	}
201	
202	function extractYamlRefs(filePath, content) {
203	  const refs = [];
204	
205	  let doc;
206	  try {
207	    doc = yaml.parseDocument(content);
208	  } catch {
209	    return refs; // Skip unparseable YAML (schema validator handles this)
210	  }
211	
212	  function checkValue(value, range, keyPath) {
213	    if (typeof value !== 'string') return;
214	    if (!isResolvable(value)) return;
215	
216	    const line = range ? offsetToLine(content, range[0]) : undefined;
217	
218	    // Check for {project-root}/_bmad/ refs
219	    const prMatch = value.match(/\{project-root\}\/_bmad\/[^\s'"<>})\]`]+/);
220	    if (prMatch) {
221	      refs.push({ file: filePath, raw: prMatch[0], type: 'project-root', line, key: keyPath });
222	    }
223	
224	    // Check for {_bmad}/ refs
225	    const bmMatch = value.match(/\{_bmad\}\/[^\s'"<>})\]`]+/);
226	    if (bmMatch) {
227	      refs.push({ file: filePath, raw: bmMatch[0], type: 'project-root', line, key: keyPath });
228	    }
229	
230	    // Check for relative paths
231	    const relMatch = value.match(/^\.\.?\/[^\s'"<>})\]`]+\.(?:md|yaml|yml|xml|json|csv|txt)$/);
232	    if (relMatch) {
233	      refs.push({ file: filePath, raw: relMatch[0], type: 'relative', line, key: keyPath });
234	    }
235	  }
236	
237	  function walkNode(node, keyPath) {
238	    if (!node) return;
239	
240	    if (yaml.isMap(node)) {
241	      for (const item of node.items) {
242	        const key = item.key && item.key.value !== undefined ? item.key.value : '?';
243	        const childPath = keyPath ? `${keyPath}.${key}` : String(key);
244	        walkNode(item.value, childPath);
245	      }
246	    } else if (yaml.isSeq(node)) {
247	      for (const [i, item] of node.items.entries()) {
248	        walkNode(item, `${keyPath}[${i}]`);
249	      }
250	    } else if (yaml.isScalar(node)) {
251	      checkValue(node.value, node.range, keyPath);
252	    }
253	  }
254	
255	  walkNode(doc.contents, '');
256	  return refs;
257	}
258	
259	function offsetToLine(content, offset) {
260	  let line = 1;
261	  for (let i = 0; i < offset && i < content.length; i++) {
262	    if (content[i] === '\n') line++;
263	  }
264	  return line;
265	}
266	
267	function extractMarkdownRefs(filePath, content) {
268	  const refs = [];
269	  const stripped = stripJsonExampleBlocks(stripCodeBlocks(content));
270	
271	  function runPattern(regex, type) {
272	    regex.lastIndex = 0;
273	    let match;
274	    while ((match = regex.exec(stripped)) !== null) {
275	      const raw = match[1];
276	      if (!isResolvable(raw)) continue;
277	      refs.push({ file: filePath, raw, type, line: offsetToLine(stripped, match.index) });
278	    }
279	  }
280	
281	  // {project-root}/_bmad/ refs
282	  runPattern(PROJECT_ROOT_REF, 'project-root');
283	
284	  // {_bmad}/ shorthand
285	  runPattern(BMAD_SHORTHAND_REF, 'project-root');
286	
287	  // exec="..." attributes
288	  runPattern(EXEC_ATTR, 'exec-attr');
289	
290	  // <invoke-task> tags
291	  runPattern(INVOKE_TASK, 'invoke-task');
292	
293	  // Step metadata
294	  runPattern(STEP_META, 'relative');
295	
296	  // Load directives
297	  runPattern(LOAD_DIRECTIVE, 'relative');
298	
299	  // Relative paths in quotes
300	  runPattern(RELATIVE_PATH_QUOTED, 'relative');
301	  runPattern(RELATIVE_PATH_DOT, 'relative');
302	
303	  return refs;
304	}
305	
306	function extractCsvRefs(filePath, content) {
307	  const refs = [];
308	
309	  let records;
310	  try {
311	    records = parseCsv(content, {
312	      columns: true,
313	      skip_empty_lines: true,
314	      relax_column_count: true,
315	    });
316	  } catch (error) {
317	    // No CSV schema validator exists yet (planned as Layer 2c) — surface parse errors visibly.
318	    // YAML equivalent (line ~198) defers to validate-agent-schema.js; CSV has no such fallback.
319	    const rel = path.relative(PROJECT_ROOT, filePath);
320	    console.error(`  [CSV-PARSE-ERROR] ${rel}: ${error.message}`);
321	    if (process.env.GITHUB_ACTIONS) {
322	      console.log(`::warning file=${rel},line=1::${escapeAnnotation(`CSV parse error: ${error.message}`)}`);
323	    }
324	    return refs;
325	  }
326	
327	  // Only process if workflow-file column exists
328	  const firstRecord = records[0];
329	  if (!firstRecord || !('workflow-file' in firstRecord)) {
330	    return refs;
331	  }
332	
333	  for (const [i, record] of records.entries()) {
334	    const raw = record['workflow-file'];
335	    if (!raw || raw.trim() === '') continue;
336	    if (!isResolvable(raw)) continue;
337	    // skill: prefixed references are resolved by the IDE/CLI, not as file paths
338	    if (raw.startsWith('skill:')) continue;
339	
340	    // Line = header (1) + data row index (0-based) + 1
341	    const line = i + 2;
342	    refs.push({ file: filePath, raw, type: 'project-root', line });
343	  }
344	
345	  return refs;
346	}
347	
348	// --- Reference Resolution ---
349	
350	function resolveRef(ref) {
351	  if (ref.type === 'project-root') {
352	    return mapInstalledToSource(ref.raw);
353	  }
354	
355	  if (ref.type === 'relative') {
356	    return path.resolve(path.dirname(ref.file), ref.raw);
357	  }
358	
359	  if (ref.type === 'exec-attr') {
360	    let execPath = ref.raw;
361	    if (execPath.includes('{project-root}')) {
362	      return mapInstalledToSource(execPath);
363	    }
364	    if (execPath.includes('{_bmad}')) {
365	      return mapInstalledToSource(execPath);
366	    }
367	    if (execPath.startsWith('_bmad/')) {
368	      return mapInstalledToSource(execPath);
369	    }
370	    // Relative exec path
371	    return path.resolve(path.dirname(ref.file), execPath);
372	  }
373	
374	  if (ref.type === 'invoke-task') {
375	    // Extract file path from invoke-task content
376	    const prMatch = ref.raw.match(/\{project-root\}\/_bmad\/([^\s'"<>})\]`]+)/);
377	    if (prMatch) return mapInstalledToSource(prMatch[0]);
378	
379	    const bmMatch = ref.raw.match(/\{_bmad\}\/([^\s'"<>})\]`]+)/);
380	    if (bmMatch) return mapInstalledToSource(bmMatch[0]);
381	
382	    const bareMatch = ref.raw.match(/_bmad\/([^\s'"<>})\]`]+)/);
383	    if (bareMatch) return mapInstalledToSource(bareMatch[0]);
384	
385	    return null; // Can't resolve — skip
386	  }
387	
388	  return null;
389	}
390	
391	// --- Absolute Path Leak Detection ---
392	
393	function checkAbsolutePathLeaks(filePath, content) {
394	  const leaks = [];
395	  const stripped = stripCodeBlocks(content);
396	  const lines = stripped.split('\n');
397	
398	  for (const [i, line] of lines.entries()) {
399	    if (ABS_PATH_LEAK.test(line)) {
400	      leaks.push({ file: filePath, line: i + 1, content: line.trim() });
401	    }
402	  }
403	
404	  return leaks;
405	}
406	
407	// --- Exports (for testing) ---
408	module.exports = { extractCsvRefs };
409	
410	// --- Main ---
411	
412	if (require.main === module) {
413	  console.log(`\nValidating file references in: ${SRC_DIR}`);
414	  console.log(`Mode: ${STRICT ? 'STRICT (exit 1 on issues)' : 'WARNING (exit 0)'}${VERBOSE ? ' + VERBOSE' : ''}\n`);
415	
416	  const files = getSourceFiles(SRC_DIR);
417	  console.log(`Found ${files.length} source files\n`);
418	
419	  let totalRefs = 0;
420	  let brokenRefs = 0;
421	  let totalLeaks = 0;
422	  let filesWithIssues = 0;
423	  const allIssues = []; // Collect for $GITHUB_STEP_SUMMARY
424	
425	  for (const filePath of files) {
426	    const relativePath = path.relative(PROJECT_ROOT, filePath);
427	    const content = fs.readFileSync(filePath, 'utf-8');
428	    const ext = path.extname(filePath);
429	
430	    // Extract references
431	    let refs;
432	    if (ext === '.yaml' || ext === '.yml') {
433	      refs = extractYamlRefs(filePath, content);
434	    } else if (ext === '.csv') {
435	      refs = extractCsvRefs(filePath, content);
436	    } else {
437	      refs = extractMarkdownRefs(filePath, content);
438	    }
439	
440	    // Resolve and classify all refs before printing anything.
441	    // This avoids the confusing pattern of printing headers at two different
442	    // times depending on verbosity — collect first, then print once.
443	    const broken = [];
444	    const ok = [];
445	
446	    for (const ref of refs) {
447	      totalRefs++;
448	      const resolved = resolveRef(ref);
449	
450	      if (resolved && !fs.existsSync(resolved)) {
451	        const hasExt = path.extname(resolved) !== '';
452	        if (!hasExt) {
453	          // Extensionless path that doesn't exist — not a file, not a directory.
454	          // Flag as UNRESOLVED (distinct from BROKEN which means "file with extension not found").
455	          broken.push({ ref, resolved: path.relative(PROJECT_ROOT, resolved), kind: 'unresolved' });
456	          brokenRefs++;
457	          continue;
458	        }
459	        broken.push({ ref, resolved: path.relative(PROJECT_ROOT, resolved), kind: 'broken' });
460	        brokenRefs++;
461	        continue;
462	      }
463	
464	      if (resolved) {
465	        ok.push({ ref, tag: 'OK' });
466	      }
467	    }
468	
469	    // Check absolute path leaks
470	    const leaks = checkAbsolutePathLeaks(filePath, content);
471	    totalLeaks += leaks.length;
472	
473	    // Print results — file header appears once, in one place
474	    const hasFileIssues = broken.length > 0 || leaks.length > 0;
475	
476	    if (hasFileIssues) {
477	      filesWithIssues++;
478	      console.log(`\n${relativePath}`);
479	
480	      if (VERBOSE) {
481	        for (const { ref, tag, note } of ok) {
482	          const suffix = note ? ` (${note})` : '';
483	          console.log(`  [${tag}] ${ref.raw}${suffix}`);
484	        }
485	      }
486	
487	      for (const { ref, resolved, kind } of broken) {
488	        const location = ref.line ? `line ${ref.line}` : ref.key ? `key: ${ref.key}` : '';
489	        const tag = kind === 'unresolved' ? 'UNRESOLVED' : 'BROKEN';
490	        const detail = kind === 'unresolved' ? 'Not found as file or directory' : 'Target not found';
491	        const issueType = kind === 'unresolved' ? 'unresolved path' : 'broken ref';
492	        console.log(`  [${tag}] ${ref.raw}${location ? ` (${location})` : ''}`);
493	        console.log(`     ${detail}: ${resolved}`);
494	        allIssues.push({ file: relativePath, line: ref.line || 1, ref: ref.raw, issue: issueType });
495	        if (process.env.GITHUB_ACTIONS) {
496	          const line = ref.line || 1;
497	          console.log(
498	            `::warning file=${relativePath},line=${line}::${escapeAnnotation(`${tag === 'UNRESOLVED' ? 'Unresolved path' : 'Broken reference'}: ${ref.raw} → ${resolved}`)}`,
499	          );
500	        }
501	      }
502	
503	      for (const leak of leaks) {
504	        console.log(`  [ABS-PATH] Line ${leak.line}: ${leak.content}`);
505	        allIssues.push({ file: relativePath, line: leak.line, ref: leak.content, issue: 'abs-path' });
506	        if (process.env.GITHUB_ACTIONS) {
507	          console.log(`::warning file=${relativePath},line=${leak.line}::${escapeAnnotation(`Absolute path leak: ${leak.content}`)}`);
508	        }
509	      }
510	    } else if (VERBOSE && refs.length > 0) {
511	      console.log(`\n${relativePath}`);
512	      for (const { ref, tag, note } of ok) {
513	        const suffix = note ? ` (${note})` : '';
514	        console.log(`  [${tag}] ${ref.raw}${suffix}`);
515	      }
516	    }
517	  }
518	
519	  // Summary
520	  console.log(`\n${'─'.repeat(60)}`);
521	  console.log(`\nSummary:`);
522	  console.log(`   Files scanned: ${files.length}`);
523	  console.log(`   References checked: ${totalRefs}`);
524	  console.log(`   Broken references: ${brokenRefs}`);
525	  console.log(`   Absolute path leaks: ${totalLeaks}`);
526	
527	  const hasIssues = brokenRefs > 0 || totalLeaks > 0;
528	
529	  if (hasIssues) {
530	    console.log(`\n   ${filesWithIssues} file(s) with issues`);
531	
532	    if (STRICT) {
533	      console.log(`\n   [STRICT MODE] Exiting with failure.`);
534	    } else {
535	      console.log(`\n   Run with --strict to treat warnings as errors.`);
536	    }
537	  } else {
538	    console.log(`\n   All file references valid!`);
539	  }
540	
541	  console.log('');
542	
543	  // Write GitHub Actions step summary
544	  if (process.env.GITHUB_STEP_SUMMARY) {
545	    let summary = '## File Reference Validation\n\n';
546	    if (allIssues.length > 0) {
547	      summary += '| File | Line | Reference | Issue |\n';
548	      summary += '|------|------|-----------|-------|\n';
549	      for (const issue of allIssues) {
550	        summary += `| ${escapeTableCell(issue.file)} | ${issue.line} | ${escapeTableCell(issue.ref)} | ${issue.issue} |\n`;
551	      }
552	      summary += '\n';
553	    }
554	    summary += `**${files.length} files scanned, ${totalRefs} references checked, ${brokenRefs + totalLeaks} issues found**\n`;
555	    fs.appendFileSync(process.env.GITHUB_STEP_SUMMARY, summary);
556	  }
557	
558	  process.exit(hasIssues && STRICT ? 1 : 0);
559	}
560	
